using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

// Load and analyze the three DLLs
var basePath = "/home/runner/.nuget/packages";

var dllPaths = new[]
{
    $"{basePath}/microsoft.extensions.ai/10.6.0/lib/net9.0/Microsoft.Extensions.AI.dll",
    $"{basePath}/microsoft.extensions.ai.openai/10.6.0/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll",
    $"{basePath}/openai/2.10.0/lib/net6.0/OpenAI.dll"
};

foreach (var dllPath in dllPaths)
{
    if (!File.Exists(dllPath))
    {
        Console.WriteLine($"NOT FOUND: {dllPath}");
        continue;
    }

    Console.WriteLine($"\n{'='*80}");
    Console.WriteLine($"ANALYZING: {dllPath}");
    Console.WriteLine('='*80);

    try
    {
        var asm = Assembly.LoadFrom(dllPath);
        var publicTypes = asm.GetTypes().Where(t => t.IsPublic).OrderBy(t => t.Name);

        foreach (var type in publicTypes)
        {
            // Skip compiler-generated types
            if (type.Name.Contains("<") || type.Name.StartsWith("_"))
                continue;

            Console.WriteLine($"\n### TYPE: {type.FullName}");

            // Show interface implementations
            var interfaces = type.GetInterfaces().Where(i => i.IsPublic);
            if (interfaces.Any())
                Console.WriteLine($"  Interfaces: {string.Join(", ", interfaces.Select(i => i.Name))}");

            // Show public methods
            var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
                .Where(m => m.DeclaringType == type && !m.IsSpecialName)
                .OrderBy(m => m.Name);

            foreach (var method in methods)
            {
                var paramStr = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                Console.WriteLine($"  METHOD: {method.ReturnType.Name} {method.Name}({paramStr})");
            }

            // Show public properties
            var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
                .Where(p => p.DeclaringType == type)
                .OrderBy(p => p.Name);

            foreach (var prop in properties)
            {
                var getset = (prop.CanRead ? "get" : "") + (prop.CanWrite ? "set" : "");
                Console.WriteLine($"  PROPERTY: {prop.PropertyType.Name} {prop.Name} [{getset}]");
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"ERROR: {ex.Message}");
    }
}
