cat > /tmp/api_analyzer/ApiAnalyzer/Program.cs << 'EOF'
using System;
using System.Reflection;
using System.Linq;
using System.Text;

var basePath = "/home/runner/.nuget/packages";

var analyses = new[]
{
    ("Microsoft.Extensions.AI", $"{basePath}/microsoft.extensions.ai/10.6.0/lib/net9.0/Microsoft.Extensions.AI.dll", 
        new[] { "IChatClient", "ChatClientBuilder", "ChatMessage", "ChatRole", "ChatOptions", "AIFunction", "AIFunctionFactory", "ChatResponse", "ChatCompletion" }),

    ("Microsoft.Extensions.AI.OpenAI", $"{basePath}/microsoft.extensions.ai.openai/10.6.0/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll",
        new[] { "OpenAIChatClient", "OpenAIClientExtensions" }),

    ("OpenAI", $"{basePath}/openai/2.10.0/lib/net6.0/OpenAI.dll",
        new[] { "OpenAIClient", "ChatClient" })
};

foreach (var (name, dllPath, keyTypes) in analyses)
{
    if (!File.Exists(dllPath))
    {
        Console.WriteLine($"\n❌ NOT FOUND: {dllPath}");
        continue;
    }

    Console.WriteLine($"\n{'='*100}");
    Console.WriteLine($"📦 {name}");
    Console.WriteLine($"{'='*100}");

    try
    {
        var asm = Assembly.LoadFrom(dllPath);
        var allPublicTypes = asm.GetTypes().Where(t => t.IsPublic && !t.Name.Contains("<")).ToList();

        // First, show key types
        foreach (var typeName in keyTypes)
        {
            var type = allPublicTypes.FirstOrDefault(t => t.Name == typeName);
            if (type == null) continue;

            PrintType(type);
        }

        // Then show other relevant types
        Console.WriteLine($"\n--- Other Public Types in {name} ---");
        var otherTypes = allPublicTypes
            .Where(t => !keyTypes.Contains(t.Name) && !t.Namespace?.Contains("Internal") == true)
            .OrderBy(t => t.Name)
            .Take(20);

        foreach (var type in otherTypes)
        {
            Console.WriteLine($"  • {type.FullName}");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"ERROR: {ex.Message}\n{ex.StackTrace}");
    }
}

void PrintType(Type type)
{
    Console.WriteLine($"\n### {type.FullName}");

    var interfaces = type.GetInterfaces().Where(i => i.IsPublic && i.Namespace?.StartsWith("System") == false).OrderBy(i => i.Name);
    if (interfaces.Any())
        Console.WriteLine($"    ↳ Implements: {string.Join(", ", interfaces.Select(i => i.Name))}");

    if (type.BaseType != null && type.BaseType != typeof(object) && !type.BaseType.FullName?.StartsWith("System") == true)
        Console.WriteLine($"    ↳ Inherits: {type.BaseType.Name}");

    // Public methods
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName && m.DeclaringType == type)
        .OrderBy(m => m.Name)
        .ToList();

    if (methods.Any())
    {
        Console.WriteLine($"    Methods:");
        foreach (var method in methods.Take(15))
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => 
                $"{(p.IsOut ? "out " : "")}{(p.ParameterType.IsByRef ? "ref " : "")}{FormatType(p.ParameterType)} {p.Name}"));
            var isStatic = method.IsStatic ? "static " : "";
            Console.WriteLine($"      • {isStatic}{FormatType(method.ReturnType)} {method.Name}({parms})");
        }
        if (methods.Count > 15)
            Console.WriteLine($"      ... and {methods.Count - 15} more methods");
    }

    // Public properties
    var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .OrderBy(p => p.Name)
        .ToList();

    if (properties.Any())
    {
        Console.WriteLine($"    Properties:");
        foreach (var prop in properties.Take(10))
        {
            var getset = (prop.CanRead ? "get" : "") + (prop.CanWrite ? ";set" : "");
            Console.WriteLine($"      • {FormatType(prop.PropertyType)} {prop.Name} [{getset}]");
        }
        if (properties.Count > 10)
            Console.WriteLine($"      ... and {properties.Count - 10} more properties");
    }
}

string FormatType(Type t)
{
    if (t.IsGenericType)
    {
        var genericArgs = string.Join(", ", t.GetGenericArguments().Select(a => a.Name));
        return $"{t.Name.Substring(0, t.Name.IndexOf('`'))}<{genericArgs}>";
    }
    if (t.IsByRef)
        return FormatType(t.GetElementType()) + "&";
    return t.Name;
}
