        if (File.Exists(path))
            return Assembly.LoadFrom(path);
    }
    return null;
};

var basePath = "/home/runner/.nuget/packages";

var analyses = new[]
{
    ("Microsoft.Extensions.AI", 
        $"{basePath}/microsoft.extensions.ai/10.6.0/lib/net9.0/Microsoft.Extensions.AI.dll"),

    ("Microsoft.Extensions.AI.OpenAI", 
        $"{basePath}/microsoft.extensions.ai.openai/10.6.0/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll"),

    ("OpenAI (2.10.0)", 
        $"{basePath}/openai/2.10.0/lib/net6.0/OpenAI.dll")
};

foreach (var (name, dllPath) in analyses)
{
    if (!File.Exists(dllPath))
    {
        Console.WriteLine($"\n❌ NOT FOUND: {dllPath}");
        continue;
    }

    Console.WriteLine($"\n{'='*110}");
    Console.WriteLine($"📦 {name} - {dllPath}");
    Console.WriteLine('='*110);

    try
    {
        var asm = Assembly.LoadFrom(dllPath);
        var publicTypes = asm.GetTypes()
            .Where(t => t.IsPublic && !t.Name.Contains("<") && !t.Name.StartsWith("_"))
            .OrderBy(t => t.Namespace)
            .ThenBy(t => t.Name)
            .ToList();

        Console.WriteLine($"Total public types: {publicTypes.Count}\n");

        foreach (var type in publicTypes)
        {
            PrintDetailedType(type);
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"ERROR: {ex.Message}");
        if (ex.InnerException != null)
            Console.WriteLine($"  Inner: {ex.InnerException.Message}");
    }
}

void PrintDetailedType(Type type)
{
    var sb = new System.Text.StringBuilder();
    sb.AppendLine($"\n  📋 {type.FullName}");

    // Interfaces
    var interfaces = type.GetInterfaces()
        .Where(i => i.IsPublic && i.Namespace != null && !i.Namespace.StartsWith("System"))
        .Distinct()
        .OrderBy(i => i.Name);
    if (interfaces.Any())
        sb.AppendLine($"     ├─ Implements: {string.Join(", ", interfaces.Select(i => i.Name))}");

    // Base class
    if (type.BaseType != null && type.BaseType != typeof(object) 
        && type.BaseType.Namespace != null && !type.BaseType.Namespace.StartsWith("System"))
        sb.AppendLine($"     ├─ Inherits: {type.BaseType.Name}");

    // Methods
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
        .Where(m => m.DeclaringType == type && !m.IsSpecialName)
        .OrderBy(m => m.Name)
        .ToList();

    if (methods.Any())
    {
        sb.AppendLine($"     ├─ Methods ({methods.Count}):");
        foreach (var m in methods.Take(20))
        {
            var parms = string.Join(", ", m.GetParameters()
                .Select(p => FormatType(p.ParameterType) + " " + p.Name));
            sb.AppendLine($"     │  • {(m.IsStatic ? "static " : "")}{FormatType(m.ReturnType)} {m.Name}({parms})");
        }
        if (methods.Count > 20)
            sb.AppendLine($"     │  ... and {methods.Count - 20} more");
    }

    // Properties
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance)
        .Where(p => p.DeclaringType == type)
        .OrderBy(p => p.Name)
        .ToList();

    if (props.Any())
    {
        sb.AppendLine($"     ├─ Properties ({props.Count}):");
        foreach (var p in props.Take(15))
        {
            var access = "";
            if (p.CanRead) access += "get";
            if (p.CanWrite) access += (access.Length > 0 ? ";set" : "set");
            sb.AppendLine($"     │  • {FormatType(p.PropertyType)} {p.Name} [{access}]");
        }
        if (props.Count > 15)
            sb.AppendLine($"     │  ... and {props.Count - 15} more");
    }

    // Events
    var events = type.GetEvents(BindingFlags.Public | BindingFlags.Instance)
        .Where(e => e.DeclaringType == type)
        .OrderBy(e => e.Name)
        .ToList();

    if (events.Any())
    {
        sb.AppendLine($"     └─ Events ({events.Count}):");
        foreach (var e in events)
            sb.AppendLine($"        • {e.Name}: {FormatType(e.EventHandlerType)}");
    }

    Console.Write(sb.ToString());
}

string FormatType(Type t)
{
    if (t == null) return "null";
    if (t.IsGenericType)
    {
        var name = t.Name.Substring(0, t.Name.IndexOf('`'));
        var args = string.Join(", ", t.GetGenericArguments().Select(a => FormatType(a)));
        return $"{name}<{args}>";
    }
    if (t.IsByRef)
        return "ref " + FormatType(t.GetElementType());
    if (t.IsArray)
        return FormatType(t.GetElementType()) + "[]";
    return t.Name;
}
