using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ───────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model  = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: set the OPENAI_API_KEY environment variable.");
    Console.Error.WriteLine("Optionally set OPENAI_MODEL (default: gpt-4o-mini).");
    return 1;
}

// ── AI client with automatic function-invocation middleware ──────────────────
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ── Shared state ────────────────────────────────────────────────────────────
var notes = new List<(string Title, string Content)>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// ── Tool: SearchWeb ─────────────────────────────────────────────────────────
[Description("Search the web and return up to 5 result titles, URLs, and snippets.")]
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    // Primary: DuckDuckGo lite HTML search
    var url = $"https://lite.duckduckgo.com/lite/?q={Uri.EscapeDataString(query)}";
    var html = await httpClient.GetStringAsync(url);

    var results = new List<object>();

    var linkRx = new Regex(
        @"<a[^>]+href=""(https?://[^""]+)""[^>]*class=""result-link""[^>]*>(.*?)</a>",
        RegexOptions.IgnoreCase | RegexOptions.Singleline);
    var snippetRx = new Regex(
        @"<td[^>]*class=""result-snippet""[^>]*>(.*?)</td>",
        RegexOptions.IgnoreCase | RegexOptions.Singleline);

    var links    = linkRx.Matches(html);
    var snippets = snippetRx.Matches(html);

    for (int i = 0; i < Math.Min(links.Count, 5); i++)
    {
        var title   = StripHtml(links[i].Groups[2].Value);
        var snippet = i < snippets.Count ? StripHtml(snippets[i].Groups[1].Value) : "";
        results.Add(new { title, url = links[i].Groups[1].Value, snippet });
    }

    // Fallback: DuckDuckGo instant-answer API
    if (results.Count == 0)
    {
        var apiUrl = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
        var json = await httpClient.GetStringAsync(apiUrl);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var abs = root.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrEmpty(abs))
            results.Add(new
            {
                title   = "Summary",
                url     = root.GetProperty("AbstractURL").GetString() ?? "",
                snippet = abs
            });

        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var t in topics.EnumerateArray().Take(5))
            {
                if (t.TryGetProperty("Text", out var txt) &&
                    t.TryGetProperty("FirstURL", out var fu))
                {
                    var s = txt.GetString() ?? "";
                    results.Add(new
                    {
                        title   = Truncate(s, 80),
                        url     = fu.GetString() ?? "",
                        snippet = s
                    });
                }
            }
        }
    }

    return results.Count > 0
        ? JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true })
        : "No results found. Try a different query.";
}

// ── Tool: FetchWebPage ──────────────────────────────────────────────────────
[Description("Fetch the visible text content of a web page (first ~4000 chars).")]
async Task<string> FetchWebPage(
    [Description("The full URL to fetch")] string url)
{
    try
    {
        var html = await httpClient.GetStringAsync(url);
        var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ").Trim();
        return text.Length > 4000 ? text[..4000] + "\n[…truncated]" : text;
    }
    catch (Exception ex)
    {
        return $"Error fetching page: {ex.Message}";
    }
}

// ── Tool: SaveNote ──────────────────────────────────────────────────────────
[Description("Save a research note with a title and content. Use this to record key findings.")]
string SaveNote(
    [Description("Short title for the note")] string title,
    [Description("Detailed content of the note")] string content)
{
    notes.Add((title, content));
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    return $"Note saved: \"{title}\" (total notes: {notes.Count})";
}

// ── Tool: GetAllNotes ───────────────────────────────────────────────────────
[Description("Retrieve all previously saved research notes.")]
string GetAllNotes()
{
    if (notes.Count == 0) return "No notes saved yet.";

    var sb = new StringBuilder();
    for (int i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"── Note {i + 1}: {notes[i].Title} ──");
        sb.AppendLine(notes[i].Content);
        sb.AppendLine();
    }
    return sb.ToString();
}

// ── Register tools ──────────────────────────────────────────────────────────
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(FetchWebPage),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetAllNotes),
};

// ── Prompt for a research topic ─────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}
Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agentic loop ────────────────────────────────────────────────────
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic you must:

        1. Search the web with several varied queries to gather broad information.
        2. Fetch the most promising pages to read their full content.
        3. Save at least 3 research notes capturing key findings (with source URLs).
        4. Perform follow-up searches to fill any knowledge gaps.
        5. Retrieve all your notes, then write a well-organized, comprehensive summary
           with inline source citations.

        Be factual, cite URLs, and cover the topic from multiple angles.
        """),
    new(ChatRole.User,
        $"Please research the following topic and provide a comprehensive summary:\n\n{topic}"),
